#### 方法一：排序 + 贪心

首先将数组 $\textit{nums}$ 从小到大进行排序，然后按三个一组对 $\textit{nums}$ 进行遍历，令当前遍历的三个下标分别为 $i$, $i + 1$, $i + 2$，如果 $\textit{nums}[i + 2] - \textit{nums}[i] \gt k$，那么不可能满足条件，直接返回空数组，否则，将当前三个元素组成的子数组放入结果数组 $\textit{res}$ 中。

```C++ [sol1-C++]
class Solution {
public:
    vector<vector<int>> divideArray(vector<int>& nums, int k) {
        sort(nums.begin(), nums.end());
        int n = nums.size();
        vector<vector<int>> res;
        for (int i = 0; i < n; i += 3) {
            if (nums[i + 2] - nums[i] > k) {
                return {};
            }
            res.emplace_back(nums.begin() + i, nums.begin() + i + 3);
        }
        return res;
    }
};
```

```Go [sol1-Go]
func divideArray(nums []int, k int) [][]int {
    sort.Ints(nums)
    res := [][]int{}
    for i := 0; i < len(nums); i += 3 {
        if nums[i + 2] - nums[i] > k {
            return nil
        }
        res = append(res, nums[i : i + 3])
    }
    return res
}
