```C [sol1-C]
int cmp(const void* a, const void* b) {
    return (*(int*)a - *(int*)b);
}

int** divideArray(int* nums, int numsSize, int k, int* returnSize, int** returnColumnSizes) {
    qsort(nums, numsSize, sizeof(int), cmp);
    int** res = (int**)malloc(numsSize / 3 * sizeof(int*));
    *returnColumnSizes = (int*)malloc(numsSize / 3 * sizeof(int));
    for (int i = 0; i < numsSize; i += 3) {
        if (nums[i + 2] - nums[i] > k) {
            *returnSize = 0;
            for (int j = 0; j < i / 3; ++j) {
                free(res[j]);
            }
            free(res);
            free(*returnColumnSizes);
            return NULL;
        }
        res[i / 3] = (int*)malloc(3 * sizeof(int));
        res[i / 3][0] = nums[i];
        res[i / 3][1] = nums[i + 1];
        res[i / 3][2] = nums[i + 2];
        (*returnColumnSizes)[i / 3] = 3;
    }
    *returnSize = numsSize / 3;
    return res;
}
```

```Rust [sol1-Rust]
impl Solution {
    pub fn divide_array(mut nums: Vec<i32>, k: i32) -> Vec<Vec<i32>> {
        nums.sort();
        let mut res = Vec::new();
        for i in (0..nums.len()).step_by(3) {
            if nums[i + 2] - nums[i] > k {
                return vec![];
            }
            res.push(vec![nums[i], nums[i + 1], nums[i + 2]]);
        }
        res
    }
}
```

**复杂度分析**

- 时间复杂度：$O(n \log n)$，其中 $n$ 是数组 $\textit{nums}$ 的长度。

- 空间复杂度：$O(\log n)$。返回值不计入空间复杂度。
